namespace sv_a5cf2adc48b142598138f29c9e92b7ca.Services;

public class AppointmentService
{
    private static readonly List<string> Doctors = ["Dr. Smith", "Dr. Johnson", "Dr. Patel", "Dr. Lee"];

    private static readonly Dictionary<string, List<string>> SlotsByDoctor = new()
    {
        ["Dr. Smith"] = ["9:00 AM", "10:00 AM", "11:00 AM", "2:00 PM", "3:00 PM"],
        ["Dr. Johnson"] = ["8:00 AM", "10:00 AM", "1:00 PM", "4:00 PM"],
        ["Dr. Patel"] = ["9:00 AM", "10:30 AM", "11:30 AM", "2:30 PM"],
        ["Dr. Lee"] = ["8:30 AM", "10:00 AM", "12:00 PM", "3:30 PM"],
    };

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(Doctors);
    }

    public Task<List<string>> GetAvailableSlotsAsync(string doctor, DateOnly date)
    {
        var slots = SlotsByDoctor.GetValueOrDefault(doctor, []);
        return Task.FromResult(new List<string>(slots));
    }

    /// <summary>
    /// Validates patient + appointment data against server-side business rules.
    /// Returns a dictionary of field name → error messages. Empty means valid.
    /// </summary>
    public Task<Dictionary<string, List<string>>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, List<string>>();

        // Outstanding balance check
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(AppointmentModel.Email)] = ["Account has outstanding balance"];
        }

        // Self-pay restriction
        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            errors[nameof(AppointmentModel.Doctor)] = ["Selected doctor does not accept self-pay patients"];
        }

        // Race-condition slot check
        if (timeSlot == "10:00 AM")
        {
            errors[nameof(AppointmentModel.TimeSlot)] = ["This slot is no longer available"];
        }

        return Task.FromResult(errors);
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_a5cf2adc48b142598138f29c9e92b7ca.Services;

public class AppointmentModel : IValidatableObject
{
    [Required(ErrorMessage = "Patient name is required.")]
    public string? PatientName { get; set; }

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Enter a valid email address.")]
    public string? Email { get; set; }

    [Required(ErrorMessage = "Phone number is required.")]
    [Phone(ErrorMessage = "Enter a valid phone number.")]
    public string? Phone { get; set; }

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string? InsuranceProvider { get; set; }

    // Step 2 fields — validated only after step 1 passes

    public string? Doctor { get; set; }

    public DateOnly? AppointmentDate { get; set; }

    public string? TimeSlot { get; set; }

    [MaxLength(500, ErrorMessage = "Reason must be 500 characters or fewer.")]
    public string? Reason { get; set; }

    /// <summary>Controls which step the form is on; step-2 fields are required only when true.</summary>
    public bool IsStep2 { get; set; }

    public IEnumerable<ValidationResult> Validate(ValidationContext validationContext)
    {
        if (!IsStep2)
            yield break;

        if (string.IsNullOrWhiteSpace(Doctor))
            yield return new ValidationResult("Preferred doctor is required.", [nameof(Doctor)]);

        if (AppointmentDate is null)
            yield return new ValidationResult("Appointment date is required.", [nameof(AppointmentDate)]);
        else if (AppointmentDate <= DateOnly.FromDateTime(DateTime.Today))
            yield return new ValidationResult("Appointment date must be in the future.", [nameof(AppointmentDate)]);

        if (string.IsNullOrWhiteSpace(TimeSlot))
            yield return new ValidationResult("Time slot is required.", [nameof(TimeSlot)]);

        if (string.IsNullOrWhiteSpace(Reason))
            yield return new ValidationResult("Reason for visit is required.", [nameof(Reason)]);
    }
}

using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Forms;

namespace sv_a5cf2adc48b142598138f29c9e92b7ca.Components;

public class CustomValidator : ComponentBase
{
    [CascadingParameter]
    private EditContext? EditContext { get; set; }

    private ValidationMessageStore? messageStore;

    protected override void OnInitialized()
    {
        messageStore = new ValidationMessageStore(EditContext!);
        EditContext!.OnValidationRequested += (s, e) => messageStore.Clear();
        EditContext!.OnFieldChanged += (s, e) => messageStore.Clear(e.FieldIdentifier);
    }

    public void DisplayErrors(Dictionary<string, List<string>> errors)
    {
        foreach (var (field, messages) in errors)
        {
            foreach (var message in messages)
            {
                messageStore!.Add(EditContext!.Field(field), message);
            }
        }
        EditContext!.NotifyValidationStateChanged();
    }

    public void ClearErrors()
    {
        messageStore?.Clear();
        EditContext?.NotifyValidationStateChanged();
    }
}

