@page "/book-appointment"
@rendermode InteractiveServer
@using sv_a5cf2adc48b142598138f29c9e92b7ca.Services
@inject AppointmentService AppointmentService

<h2>Book an Appointment</h2>

<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    <h3>Step 1: Patient Information</h3>

    <div>
        <label>
            Patient Name:
            <InputText @bind-Value="model.PatientName" />
            <ValidationMessage For="() => model.PatientName" />
        </label>
    </div>

    <div>
        <label>
            Email:
            <InputText @bind-Value="model.Email" />
            <ValidationMessage For="() => model.Email" />
        </label>
    </div>

    <div>
        <label>
            Phone:
            <InputText @bind-Value="model.Phone" />
            <ValidationMessage For="() => model.Phone" />
        </label>
    </div>

    <div>
        <label>
            Insurance Provider:
            <InputSelect @bind-Value="model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => model.InsuranceProvider" />
        </label>
    </div>

    @if (!showStep2)
    {
        <button type="button" @onclick="CheckAvailability" disabled="@isProcessing">
            @(isProcessing ? "Checking..." : "Check Availability")
        </button>
    }

    @if (showStep2)
    {
        <h3>Step 2: Appointment Details</h3>

        <div>
            <label>
                Preferred Doctor:
                <InputSelect @bind-Value="model.Doctor" @bind-Value:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.Doctor" />
            </label>
        </div>

        <div>
            <label>
                Date:
                <InputDate @bind-Value="model.AppointmentDate" @bind-Value:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="() => model.AppointmentDate" />
            </label>
        </div>

        <div>
            <label>
                Time Slot:
                <InputSelect @bind-Value="model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.TimeSlot" />
            </label>
        </div>

        <div>
            <label>
                Reason for Visit:
                <InputTextArea @bind-Value="model.Reason" />
                <ValidationMessage For="() => model.Reason" />
            </label>
        </div>

        <button type="submit" disabled="@isProcessing">
            @(isProcessing ? "Submitting..." : "Book Appointment")
        </button>
    }
</EditForm>

@if (isBooked)
{
    <p><strong>Appointment booked successfully!</strong></p>
}

@code {
    private AppointmentModel model = new();
    private EditContext editContext = default!;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isProcessing;
    private bool isBooked;

    private List<string> doctors = [];
    private List<string> availableSlots = [];

    protected override void OnInitialized()
    {
        editContext = new EditContext(model);
    }

    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();

        // Validate only step 1 (IsStep2 is false, so step-2 [Required] won't fire)
        model.IsStep2 = false;
        if (!editContext.Validate())
            return;

        isProcessing = true;
        try
        {
            doctors = await AppointmentService.GetDoctorsAsync();
            showStep2 = true;
        }
        finally
        {
            isProcessing = false;
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        if (!string.IsNullOrWhiteSpace(model.Doctor) && model.AppointmentDate is not null)
        {
            availableSlots = await AppointmentService.GetAvailableSlotsAsync(
                model.Doctor, model.AppointmentDate.Value);
            model.TimeSlot = null;
        }
    }

    private async Task HandleSubmit()
    {
        customValidator?.ClearErrors();

        // Re-validate with step-2 rules
        model.IsStep2 = true;
        if (!editContext.Validate())
            return;

        isProcessing = true;
        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                model.Email!, model.InsuranceProvider!, model.Doctor!, model.TimeSlot!);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            isBooked = true;
        }
        finally
        {
            isProcessing = false;
        }
    }
}

